export function detectLanguage(languages = globalThis.navigator?.languages || [globalThis.navigator?.language]) {
  for (const value of languages || []) {
    const language = String(value || "").trim().toLowerCase().split(/[-_]/)[0];
    if (SUPPORTED_LANGUAGES.includes(language)) return language;
  }
  return "en";
}

export const language = detectLanguage();
export const locale = ({ en: "en-GB", fr: "fr-FR", es: "es-ES", it: "it-IT", pt: "pt-PT", de: "de-DE" })[language];

const languageIndex = ({ fr: 0, en: 1, es: 2, it: 3, pt: 4, de: 5 })[language];
const catalogue = new Map(rows.map((row) => [row[0], row[languageIndex]]));

export function t(source, values = {}) {
  let translated = language === "fr" ? source : (catalogue.get(source) || source);
  for (const [key, value] of Object.entries(values)) {
    translated = translated.replaceAll(`{${key}}`, String(value));
  }
  return translated;
}

function translateTextNode(node) {
  const source = node.nodeValue;
  const trimmed = source.trim();
  if (!trimmed) return;
  const translated = t(trimmed);
  if (translated !== trimmed) node.nodeValue = source.replace(trimmed, translated);
}

export function localizeElement(element) {
  for (const attribute of ["title", "aria-label", "placeholder"]) {
    if (!element.hasAttribute?.(attribute)) continue;
    const source = element.getAttribute(attribute);
    const translated = t(source);
    if (translated !== source) element.setAttribute(attribute, translated);
  }
}

export function localizeDocument(root = document) {
  const doc = root.ownerDocument || root;
  doc.documentElement.lang = language;
  const walker = doc.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      return /^(SCRIPT|STYLE|TEXTAREA)$/.test(node.parentElement?.tagName || "")
        ? NodeFilter.FILTER_REJECT
        : NodeFilter.FILTER_ACCEPT;
    },
  });
  while (walker.nextNode()) translateTextNode(walker.currentNode);
  if (root.querySelectorAll) {
    localizeElement(root.documentElement || root);
    for (const element of root.querySelectorAll("[title], [aria-label], [placeholder]")) localizeElement(element);
  }
}

export { SUPPORTED_LANGUAGES };
